        it("llama-server qwen3coder30b leaking <tool_call>\n<function name=... - from mixed content + tool_call in one response", function()
            -- FYI this is just temporary until the llama-server backend can detect and not leak the start of a tool_call
            -- part of issue IIUC is that hermes tool call format is triggered (in part b/c of how they prompt the model)
            --  and when streaming results, after content starts, it doesn't hold back content deltas, even if they start matching the hermes tool call regex
            --  mixed content AFAICT always ends with the tool call in my testing
            -- join content together
            --  cat lua/ask-openai/tools/tests/captures/weather-mixed-content-toolcall-sses.json | jq ".choices[0].delta.content" -r | grep -v null | string join ""

            -- FYI see llama-server-tool-call.md for full response capture
            local sses_json = vim.fn.readfile("lua/ask-openai/tools/tests/captures/weather-mixed-content-toolcall-sses.json")
            -- vim.print(ss_events)
            local frontend = FakeFrontend:new()
            local request = { accumulated_model_response_messages = {} }

            local sses = vim.iter(sses_json)
                :map(function(line)
                    return vim.json.decode(line, {})
                end)
                :each(function(sse_parsed)
                    local choices = sse_parsed.choices
                    -- vim.print(sse[1])
                    agents_frontend.on_streaming_delta_update_message_history(choices[1], request, sse_parsed)
                end)

            should.be_equal(1, #request.accumulated_model_response_messages)

            local rx_message = request.accumulated_model_response_messages[1]
            should.be_equal(0, rx_message.index)

            local content_only = "Hi there! Let me check the current weather for Washington DC for you."
            local tool_call_only = "\n<tool_call>\n<function=get_current_weather"
            local mixed = content_only .. tool_call_only
            should.be_equal(mixed, rx_message._verbatim_content)
